package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.Objects;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testSetFieldNamingStrategy_withValidStrategy_shouldSetFieldAndReturnThis() throws Exception {
    FieldNamingStrategy mockStrategy = mock(FieldNamingStrategy.class);

    GsonBuilder returned = gsonBuilder.setFieldNamingStrategy(mockStrategy);

    assertSame(gsonBuilder, returned);

    // Use reflection to access private field fieldNamingPolicy
    Field field = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);

    assertSame(mockStrategy, fieldValue);
  }

  @Test
  void testSetFieldNamingStrategy_withNull_shouldThrowNullPointerException() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.setFieldNamingStrategy(null));
  }

}
